from abc import ABC,abstractmethod
from typing import Any
from vnstock_news.utils.logger import setup_logger
class BaseParser(ABC):
	def __init__(A,show_log:bool=False):A.logger=setup_logger(A.__class__.__name__,show_log)
	@abstractmethod
	def fetch(self)->Any:0
	@abstractmethod
	def parse(self,raw:Any)->Any:0
	def run(A)->Any:B=A.fetch();return A.parse(B)